<template>
    <div class='first1-list'>
        <!-- <p style='width: 200px;height:100px;background: #000;color:#fff;font-size:24px;' @click='testGrowingIo'>testGrowingIo</p> -->
        <div class='container-left'>淡泊以明誌</div>
        <h1 style='color:#9D39A6;display:inline-block;padding:10px 20px;border:1px #AD3089 solid;border-radius:20px;margin-top:15px;'>
            依依: {{birthdy}}
        </h1>
        <div class='container'>
            <ul class='person-data'>
                <li></li>
                <li>
                    <img width='150px' src="/images/phone.jpg" alt="">
                    <div class='face'></div>
                </li>
                <li></li>
            </ul>
            <p>Daily phrases</p>
            <el-button @click='change()'>translate</el-button>
            <ul>
                <li 
                    v-for='(item, index) in everyDayEng' 
                    :key='index' 
                    :class='{bgp:showCn && index !== checkIndex, "li-active":index === checkIndex}' 
                    @click='check(index)'>
                    <span>{{ item.id + ': ' + item.value}}</span>
                    <span v-if='showCn'> →→→→→ {{item.cn}}</span>
                </li>
            </ul>
            <br/>
            <p>Aphorism</p>
            <ul>
                <li 
                    style='font-size: 24px;font-family: KaiTi'
                    v-for='(item, index) in aphorism' 
                    :key='index'>
                    {{ (index + 1) + '. ' + item.value}}
                </li>
            </ul>
            <div class='color-list'>
                <ul>
                    <li v-for='(item, index) in colorList' :key='index'>
                        <span>{{ item.name }}</span>
                        <span>{{ item.color }}</span>
                        <span>{{ item.hexColorValue }}</span>
                        <span :style='{background: item.color}'></span>
                    </li>
                </ul>
            </div>
        </div>
        <div class='container-left'>寧靜以致遠</div>
    </div>
</template>
<script>
    import {everyDay, aphorism, colorList} from '../js/first';
    export default {
        data() {
            return {
                everyDayEng: everyDay,
                aphorism: aphorism,
                colorList: colorList,
                showCn:false,
                checkIndex: 0,
                html: 'www.test9.zhixueyun.com',
                color: 'red',
                birthdy: ''
            };
        },
        created() {
            this.calcBirthDay()
        },
        methods: {
            change() {
                this.showCn = !this.showCn;
            },
            check(index) {
                this.checkIndex = index;
            },
            testGrowingIo() {
                console.log('testGrowingIo')
            },
            calcBirthDay() {
                const vm = this;
                setInterval(()=> {
                    const birthdy = '2020/08/12 11:24';
                    const current = new Date().getTime() / 1000;
                    const old = new Date(birthdy).getTime() / 1000;
                    const differ = current - old;
                    const day = parseInt(differ / (3600 * 24))
                    const hour = parseInt(differ / 3600) % 24;
                    const min = parseInt(differ / 60) % 60;
                    const s = parseInt(differ % 60); 
                    vm.birthdy = `${day}天${hour}小时${min}分钟${s}秒`;
                },1000)
                
            }
        }
    };
</script>